using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Moq;

namespace ContosoUniversity.Tests;

public static class TestHelpers
{
    public static SchoolContext CreateInMemoryContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        var context = new SchoolContext(options);
        return context;
    }

    public static SchoolContext CreateSeededContext(string? dbName = null)
    {
        var context = CreateInMemoryContext(dbName);
        SeedDatabase(context);
        return context;
    }

    public static void SeedDatabase(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11")
        };
        var instructor2 = new Instructor
        {
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06")
        };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        var dept1 = new Department
        {
            Name = "English",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor1.ID
        };
        var dept2 = new Department
        {
            Name = "Mathematics",
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructor2.ID
        };
        context.Departments.AddRange(dept1, dept2);
        context.SaveChanges();

        var course1 = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = dept1.DepartmentID
        };
        var course2 = new Course
        {
            CourseID = 4022,
            Title = "Microeconomics",
            Credits = 3,
            DepartmentID = dept2.DepartmentID
        };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        var student1 = new Student
        {
            FirstMidName = "Carson",
            LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2010-09-01")
        };
        var student2 = new Student
        {
            FirstMidName = "Meredith",
            LastName = "Alonso",
            EnrollmentDate = DateTime.Parse("2012-09-01")
        };
        var student3 = new Student
        {
            FirstMidName = "Arturo",
            LastName = "Anand",
            EnrollmentDate = DateTime.Parse("2013-09-01")
        };
        context.Students.AddRange(student1, student2, student3);
        context.SaveChanges();

        context.Enrollments.AddRange(
            new Enrollment { StudentID = student1.ID, CourseID = course1.CourseID, Grade = Grade.A },
            new Enrollment { StudentID = student2.ID, CourseID = course2.CourseID, Grade = Grade.B }
        );
        context.SaveChanges();

        // Add course assignments
        context.CourseAssignments.AddRange(
            new CourseAssignment { CourseID = course1.CourseID, InstructorID = instructor1.ID },
            new CourseAssignment { CourseID = course2.CourseID, InstructorID = instructor2.ID }
        );
        context.SaveChanges();

        // Add office assignment
        context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = instructor2.ID,
            Location = "Smith 17"
        });
        context.SaveChanges();
    }

    public static void SetupControllerContext(Controller controller)
    {
        var httpContext = new DefaultHttpContext();
        controller.ControllerContext = new ControllerContext
        {
            HttpContext = httpContext
        };
        controller.TempData = new TempDataDictionary(httpContext, Mock.Of<ITempDataProvider>());
    }
}

