using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new StudentsController(_context);
        TestHelpers.SetupControllerContext(_controller);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewResult_WithStudentList()
    {
        var result = _controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Index_WithSearchString_FiltersStudents()
    {
        var result = _controller.Index(null, null, "Alexander", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_WithNameDescSort_SortsDescending()
    {
        var result = _controller.Index("name_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.True(model.Count >= 2);
        // name_desc: descending by LastName
        Assert.True(string.Compare(model[0].LastName, model[1].LastName) >= 0);
    }

    [Fact]
    public void Index_WithDateSort_SortsByDateAscending()
    {
        var result = _controller.Index("Date", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.True(model.Count >= 2);
        Assert.True(model[0].EnrollmentDate <= model[1].EnrollmentDate);
    }

    [Fact]
    public void Index_WithDateDescSort_SortsByDateDescending()
    {
        var result = _controller.Index("date_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.True(model.Count >= 2);
        Assert.True(model[0].EnrollmentDate >= model[1].EnrollmentDate);
    }

    [Fact]
    public void Index_DefaultSort_SortsByLastNameAscending()
    {
        var result = _controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.True(model.Count >= 2);
        Assert.True(string.Compare(model[0].LastName, model[1].LastName) <= 0);
    }

    [Fact]
    public void Index_WithNewSearchString_ResetsPageTo1()
    {
        var result = _controller.Index(null, null, "Alex", 3);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_WithCurrentFilter_UsesExistingFilter()
    {
        var result = _controller.Index(null, "Alexander", null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagSortParameters()
    {
        var result = _controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
        Assert.Equal("Date", _controller.ViewBag.DateSortParm);
    }

    [Fact]
    public void Index_WithNameDescSort_SetsCorrectViewBag()
    {
        _controller.Index("name_desc", null, null, null);
        Assert.Equal("", _controller.ViewBag.NameSortParm);
    }

    [Fact]
    public void Index_WithDateSort_SetsDateDescViewBag()
    {
        _controller.Index("Date", null, null, null);
        Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
    }

    [Fact]
    public void Index_SearchByFirstName_ReturnsMatch()
    {
        var result = _controller.Index(null, null, "Carson", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Carson", model[0].FirstMidName);
    }

    #endregion

    #region Details

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_WithValidId_ReturnsViewWithStudent()
    {
        var student = _context.Students.First();

        var result = _controller.Details(student.ID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void Details_IncludesEnrollmentsWithCourse()
    {
        var student = _context.Students.First();

        var result = _controller.Details(student.ID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        // Student should have enrollments loaded
        Assert.NotNull(model.Enrollments);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        var result = _controller.Create(student);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_Post_ValidStudent_AddsToDatabase()
    {
        var initialCount = _context.Students.Count();
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        _controller.Create(student);

        Assert.Equal(initialCount + 1, _context.Students.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        var result = _controller.Create(student);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Create_Post_MinDateEnrollment_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_DefaultDateEnrollment_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = default(DateTime)
        };

        var result = _controller.Create(student);

        Assert.False(_controller.ModelState.IsValid);
    }

    #endregion

    #region Edit

    [Fact]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_WithValidId_ReturnsViewWithStudent()
    {
        var student = _context.Students.First();

        var result = _controller.Edit(student.ID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        var student = _context.Students.AsNoTracking().First();
        student.LastName = "UpdatedName";

        var result = _controller.Edit(student);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_Post_ValidStudent_UpdatesDatabase()
    {
        var student = _context.Students.AsNoTracking().First();
        student.LastName = "UpdatedLastName";

        _controller.Edit(student);

        var updated = _context.Students.Find(student.ID);
        Assert.Equal("UpdatedLastName", updated!.LastName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = _context.Students.AsNoTracking().First();

        var result = _controller.Edit(student);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Edit_Post_MinDateEnrollment_ReturnsViewWithError()
    {
        var student = _context.Students.AsNoTracking().First();
        student.EnrollmentDate = DateTime.MinValue;

        var result = _controller.Edit(student);

        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_WithValidId_ReturnsViewWithStudent()
    {
        var student = _context.Students.First();

        var result = _controller.Delete(student.ID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void DeleteConfirmed_RemovesStudentFromDatabase()
    {
        var student = _context.Students.First();
        var initialCount = _context.Students.Count();

        _controller.DeleteConfirmed(student.ID);

        Assert.Equal(initialCount - 1, _context.Students.Count());
    }

    [Fact]
    public void DeleteConfirmed_RedirectsToIndex()
    {
        var student = _context.Students.First();

        var result = _controller.DeleteConfirmed(student.ID);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    #endregion
}

using ContosoUniversity.Controllers;
