    {
        var instructor = _context.Instructors.First();
        var courseAssignment = _context.CourseAssignments
            .Where(ca => ca.InstructorID == instructor.ID)
            .First();

        // Add an enrollment for the course
        var student = _context.Students.First();
        var enrollment = new Enrollment
        {
            StudentID = student.ID,
            CourseID = courseAssignment.CourseID,
            Grade = Grade.A
        };
        // Check if enrollment exists first
        if (!_context.Enrollments.Any(e => e.StudentID == student.ID && e.CourseID == courseAssignment.CourseID))
        {
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();
        }

        var result = _controller.Index(instructor.ID, courseAssignment.CourseID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Enrollments);
    }

