{"file_text": "using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any leftover notifications from other tests
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        // Drain to prevent cross-test contamination
        while (_service.ReceiveNotification() != null) { }
        _service.Dispose();
    }

    #region SendNotification

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Doe", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesEntityId()
    {
        _service.SendNotification("Course", "42", EntityOperation.UPDATE, "System");

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 42", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _service.SendNotification("Department", "5", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        _service.SendNotification("Student", "1", "Alice", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("New", notification.Message);
        Assert.Contains("created", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        _service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("deleted", notification.Message);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.InRange(notification.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_SetsIsReadToFalse()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.False(notification.IsRead);
    }

    #endregion

    #region ReceiveNotification

    [Fact]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        var result = _service.ReceiveNotification();

        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_ReturnsInFIFOOrder()
    {
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        var third = _service.ReceiveNotification();

        Assert.Equal("A", first!.EntityType);
        Assert.Equal("B", second!.EntityType);
        Assert.Equal("C", third!.EntityType);
    }

    [Fact]
    public void ReceiveNotification_RemovesFromQueue()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        Assert.NotNull(first);
        Assert.Null(second);
    }

    #endregion

    #region MarkAsRead

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation, just verify it doesn't throw
        var exception = Record.Exception(() => _service.MarkAsRead(1));
        Assert.Null(exception);
    }

    [Fact]
    public void MarkAsRead_WithAnyId_CompletesSuccessfully()
    {
        var exception = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(exception);
    }

    #endregion

    #region Dispose

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        var service = new NotificationService();
        var exception = Record.Exception(() =>
        {
            service.Dispose();
            service.Dispose();
        });
        Assert.Null(exception);
    }

    #endregion

    #region Queue Capacity

    [Fact]
    public void SendNotification_ExceedingMaxCapacity_EvictsOldest()
    {
        // Queue max is 500, send more than that
        for (int i = 0; i < 510; i++)
        {
            _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Should still be able to receive (queue was trimmed but not empty)
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
    }

    #endregion
}
