using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;
    private readonly string _tempWebRoot;

    public CoursesControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _envMock = new Mock<IWebHostEnvironment>();
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _tempWebRoot = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
        Directory.CreateDirectory(_tempWebRoot);
        _envMock.Setup(e => e.WebRootPath).Returns(_tempWebRoot);
        _envMock.Setup(e => e.ContentRootPath).Returns(_tempWebRoot);
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        TestHelpers.SetupControllerContext(_controller);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempWebRoot))
        {
            try { Directory.Delete(_tempWebRoot, true); } catch { }
        }
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewResult_WithCourseList()
    {
        var result = _controller.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Index_IncludesDepartment()
    {
        var result = _controller.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
        Assert.All(model, c => Assert.NotNull(c.Department));
    }

    #endregion

    #region Details

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_WithValidId_ReturnsViewWithCourse()
    {
        var course = _context.Courses.First();

        var result = _controller.Details(course.CourseID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal(course.CourseID, model.CourseID);
        Assert.NotNull(model.Department);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithDepartmentSelectList()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
        Assert.IsType<Course>(viewResult.Model);
    }

    [Fact]
    public void Create_Post_ValidCourse_RedirectsToIndex()
    {
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };

        var result = _controller.Create(course, null!);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_Post_ValidCourse_AddsToDatabase()
    {
        var dept = _context.Departments.First();
        var initialCount = _context.Courses.Count();
        var course = new Course
        {
            CourseID = 8888,
            Title = "Another Course",
            Credits = 4,
            DepartmentID = dept.DepartmentID
        };

        _controller.Create(course, null!);

        Assert.Equal(initialCount + 1, _context.Courses.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course();

        var result = _controller.Create(course, null!);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Create_Post_WithInvalidImageExtension_ReturnsViewWithError()
    {
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 7777,
            Title = "Image Test",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.exe");
        fileMock.Setup(f => f.Length).Returns(1024);

        var result = _controller.Create(course, fileMock.Object);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_WithOversizedImage_ReturnsViewWithError()
    {
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 6666,
            Title = "Big Image Test",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.jpg");
        fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

        var result = _controller.Create(course, fileMock.Object);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_WithValidImage_SavesFileAndRedirects()
    {
        var dept = _context.Departments.First();
        var course = new Course
        {
            CourseID = 5555,
            Title = "Image Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.png");
        fileMock.Setup(f => f.Length).Returns(1024);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        var result = _controller.Create(course, fileMock.Object);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.NotNull(course.TeachingMaterialImagePath);
        Assert.Contains("/Uploads/TeachingMaterials/", course.TeachingMaterialImagePath);
    }

    #endregion

    #region Edit

    [Fact]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_WithValidId_ReturnsViewWithCourse()
    {
        var course = _context.Courses.First();

        var result = _controller.Edit(course.CourseID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal(course.CourseID, model.CourseID);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Edit_Post_ValidCourse_RedirectsToIndex()
    {
        var course = _context.Courses.AsNoTracking().First();
        course.Title = "Updated Title";

        var result = _controller.Edit(course, null!);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_Post_ValidCourse_UpdatesDatabase()
    {
        var course = _context.Courses.AsNoTracking().First();
        course.Title = "Updated Course Title";

        _controller.Edit(course, null!);

        var updated = _context.Courses.Find(course.CourseID);
        Assert.Equal("Updated Course Title", updated!.Title);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = _context.Courses.AsNoTracking().First();

        var result = _controller.Edit(course, null!);

        Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Edit_Post_WithInvalidImageExtension_ReturnsViewWithError()
    {
        var course = _context.Courses.AsNoTracking().First();
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("bad.txt");
        fileMock.Setup(f => f.Length).Returns(1024);

        var result = _controller.Edit(course, fileMock.Object);

        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Edit_Post_WithOversizedImage_ReturnsViewWithError()
    {
        var course = _context.Courses.AsNoTracking().First();
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("big.jpg");
        fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024);

        var result = _controller.Edit(course, fileMock.Object);

        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Edit_Post_WithValidImage_SavesAndRedirects()
    {
        var course = _context.Courses.AsNoTracking().First();
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("update.jpg");
        fileMock.Setup(f => f.Length).Returns(2048);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        var result = _controller.Edit(course, fileMock.Object);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_WithValidId_ReturnsViewWithCourse()
    {
        var course = _context.Courses.First();

        var result = _controller.Delete(course.CourseID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal(course.CourseID, model.CourseID);
    }

    [Fact]
    public void DeleteConfirmed_RemovesCourseFromDatabase()
    {
        var course = _context.Courses.First();
        var initialCount = _context.Courses.Count();

        _controller.DeleteConfirmed(course.CourseID);

        Assert.Equal(initialCount - 1, _context.Courses.Count());
    }

    [Fact]
    public void DeleteConfirmed_RedirectsToIndex()
    {
        var course = _context.Courses.First();

        var result = _controller.DeleteConfirmed(course.CourseID);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void DeleteConfirmed_WithImagePath_DeletesFile()
    {
        // Set up a course with an image file
        var uploadsPath = Path.Combine(_tempWebRoot, "Uploads", "TeachingMaterials");
        Directory.CreateDirectory(uploadsPath);
        var testFile = Path.Combine(uploadsPath, "test_image.jpg");
        File.WriteAllText(testFile, "fake image");

        var course = _context.Courses.First();
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
        _context.SaveChanges();

        _controller.DeleteConfirmed(course.CourseID);

        Assert.False(File.Exists(testFile));
    }

    #endregion
}

