using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly DepartmentsController _controller;

    public DepartmentsControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new DepartmentsController(_context);
        TestHelpers.SetupControllerContext(_controller);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

    [Fact]
    public void Index_ReturnsViewResult_WithDepartmentList()
    {
        var result = _controller.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Department>>(viewResult.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Index_IncludesAdministratorNavigation()
    {
        var result = _controller.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Department>>(viewResult.Model);
        // Departments that have an InstructorID should have Administrator loaded
        var deptWithAdmin = model.Where(d => d.InstructorID != null).ToList();
        Assert.All(deptWithAdmin, d => Assert.NotNull(d.Administrator));
    }

    #endregion

    #region Details

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_WithValidId_ReturnsViewWithDepartment()
    {
        var dept = _context.Departments.First();

        var result = _controller.Details(dept.DepartmentID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithInstructorSelectList()
    {
        var result = _controller.Create();

        Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        var instructor = _context.Instructors.First();
        var department = new Department
        {
            Name = "Science",
            Budget = 200000,
            StartDate = DateTime.Parse("2020-09-01"),
            InstructorID = instructor.ID
        };

        var result = _controller.Create(department);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_Post_ValidDepartment_AddsToDatabase()
    {
        var initialCount = _context.Departments.Count();
        var instructor = _context.Instructors.First();
        var department = new Department
        {
            Name = "Physics",
            Budget = 150000,
            StartDate = DateTime.Parse("2020-09-01"),
            InstructorID = instructor.ID
        };

        _controller.Create(department);

        Assert.Equal(initialCount + 1, _context.Departments.Count());
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department();

        var result = _controller.Create(department);

        Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    #endregion

    #region Edit

    [Fact]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_WithValidId_ReturnsViewWithDepartment()
    {
        var dept = _context.Departments.First();

        var result = _controller.Edit(dept.DepartmentID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = _context.Departments.AsNoTracking().First();
        dept.Name = "Updated Department";

        var result = _controller.Edit(dept);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_UpdatesDatabase()
    {
        var dept = _context.Departments.AsNoTracking().First();
        dept.Name = "Renamed Department";

        _controller.Edit(dept);

        var updated = _context.Departments.Find(dept.DepartmentID);
        Assert.Equal("Renamed Department", updated!.Name);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = _context.Departments.AsNoTracking().First();

        var result = _controller.Edit(dept);

        Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_WithValidId_ReturnsViewWithDepartment()
    {
        var dept = _context.Departments.First();

        var result = _controller.Delete(dept.DepartmentID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    [Fact]
    public void DeleteConfirmed_RemovesDepartmentFromDatabase()
    {
        // Create a department with no course dependencies
        var dept = new Department
        {
            Name = "ToDelete",
            Budget = 50000,
            StartDate = DateTime.Now
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        var initialCount = _context.Departments.Count();

        _controller.DeleteConfirmed(dept.DepartmentID);

        Assert.Equal(initialCount - 1, _context.Departments.Count());
    }

    [Fact]
    public void DeleteConfirmed_RedirectsToIndex()
    {
        var dept = new Department
        {
            Name = "DeleteMe",
            Budget = 10000,
            StartDate = DateTime.Now
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(dept.DepartmentID);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    #endregion
}

