using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new InstructorsController(_context);
        TestHelpers.SetupControllerContext(_controller);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index

    [Fact]
    public void Index_WithNoParameters_ReturnsViewWithInstructors()
    {
        var result = _controller.Index(null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Instructors);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        var instructor = _context.Instructors.First();

        var result = _controller.Index(instructor.ID, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Courses);
        Assert.NotEmpty(model.Courses);
    }

    [Fact]
    public void Index_WithInstructorId_SetsViewBagInstructorID()
    {
        var instructor = _context.Instructors.First();

        _controller.Index(instructor.ID, null);

        Assert.Equal(instructor.ID, _controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Index_WithInstructorIdAndCourseId_PopulatesEnrollments()
    {
        var instructor = _context.Instructors.First();
        var courseAssignment = _context.CourseAssignments
            .Where(ca => ca.InstructorID == instructor.ID)
            .First();

        // Add an enrollment for the course
        var student = _context.Students.First();
        var enrollment = new Enrollment
        {
            StudentID = student.ID,
            CourseID = courseAssignment.CourseID,
            Grade = Grade.A
        };
        // Check if enrollment exists first
        if (!_context.Enrollments.Any(e => e.StudentID == student.ID && e.CourseID == courseAssignment.CourseID))
        {
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();
        }

        var result = _controller.Index(instructor.ID, courseAssignment.CourseID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Enrollments);
    }

    [Fact]
    public void Index_InstructorsAreOrderedByLastName()
    {
        var result = _controller.Index(null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        var instructors = model.Instructors.ToList();
        for (int i = 1; i < instructors.Count; i++)
        {
            Assert.True(string.Compare(instructors[i - 1].LastName, instructors[i].LastName) <= 0);
        }
    }

    #endregion

    #region Details

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_WithValidId_ReturnsViewWithInstructor()
    {
        var instructor = _context.Instructors.First();

        var result = _controller.Details(instructor.ID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal(instructor.ID, model.ID);
    }

    #endregion

    #region Create

    [Fact]
    public void Create_Get_ReturnsViewWithInstructorAndAssignedCourses()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.NotNull(model.CourseAssignments);
        Assert.Empty(model.CourseAssignments);
        Assert.NotNull(_controller.ViewBag.Courses);
    }

    [Fact]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2020-01-15")
        };

        var result = _controller.Create(instructor, null!);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_Post_ValidInstructor_AddsToDatabase()
    {
        var initialCount = _context.Instructors.Count();
        var instructor = new Instructor
        {
            FirstMidName = "Added",
            LastName = "Professor",
            HireDate = DateTime.Parse("2021-06-01")
        };

        _controller.Create(instructor, null!);

        Assert.Equal(initialCount + 1, _context.Instructors.Count());
    }

    [Fact]
    public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
    {
        var courses = _context.Courses.Take(2).ToList();
        var instructor = new Instructor
        {
            FirstMidName = "Course",
            LastName = "Assigned",
            HireDate = DateTime.Parse("2021-06-01")
        };
        var selectedCourses = courses.Select(c => c.CourseID.ToString()).ToArray();

        _controller.Create(instructor, selectedCourses);

        var saved = _context.Instructors
            .Include(i => i.CourseAssignments)
            .Single(i => i.LastName == "Assigned");
        Assert.Equal(2, saved.CourseAssignments.Count);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor();

        var result = _controller.Create(instructor, null!);

        Assert.IsType<ViewResult>(result);
    }

    #endregion

    #region Delete

    [Fact]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_WithValidId_ReturnsViewWithInstructor()
    {
        var instructor = _context.Instructors.First();

        var result = _controller.Delete(instructor.ID);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal(instructor.ID, model.ID);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructorFromDatabase()
    {
        // Create a standalone instructor to avoid FK issues
        var instructor = new Instructor
        {
            FirstMidName = "ToDelete",
            LastName = "Professor",
            HireDate = DateTime.Parse("2020-01-01")
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Add an office assignment
        _context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Test Office"
        });
        _context.SaveChanges();

        var initialCount = _context.Instructors.Count();

        _controller.DeleteConfirmed(instructor.ID);

        Assert.Equal(initialCount - 1, _context.Instructors.Count());
    }

    [Fact]
    public void DeleteConfirmed_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            FirstMidName = "DeleteMe",
            LastName = "Prof",
            HireDate = DateTime.Parse("2020-01-01")
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        _context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Office"
        });
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(instructor.ID);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void DeleteConfirmed_NullsDepartmentAdministrator()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Admin",
            LastName = "Remover",
            HireDate = DateTime.Parse("2020-01-01")
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        _context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Temp"
        });
        _context.SaveChanges();

        var dept = new Department
        {
            Name = "TestDept",
            Budget = 50000,
            StartDate = DateTime.Now,
            InstructorID = instructor.ID
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        _controller.DeleteConfirmed(instructor.ID);

        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.Null(updatedDept!.InstructorID);
    }

    #endregion
}

