using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests : IDisposable
{
    private readonly SchoolContext _context;

    public SchoolContextTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
    }

    public void Dispose()
    {
        _context.Dispose();
    }

    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-01-01")
        };
        _context.Students.Add(student);
        _context.SaveChanges();

        var retrieved = _context.Students.Find(student.ID);
        Assert.NotNull(retrieved);
        Assert.Equal("Test", retrieved.FirstMidName);
        Assert.Equal("Student", retrieved.LastName);
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "Professor",
            HireDate = DateTime.Parse("2020-01-01")
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var retrieved = _context.Instructors.Find(instructor.ID);
        Assert.NotNull(retrieved);
        Assert.Equal("Test", retrieved.FirstMidName);
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        var dept = new Department
        {
            Name = "TestDept",
            Budget = 100000,
            StartDate = DateTime.Now
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = 1234,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var retrieved = _context.Courses.Find(1234);
        Assert.NotNull(retrieved);
        Assert.Equal("Test Course", retrieved.Title);
    }

    [Fact]
    public void CanAddAndRetrieveDepartment()
    {
        var department = new Department
        {
            Name = "Engineering",
            Budget = 500000,
            StartDate = DateTime.Parse("2020-09-01")
        };
        _context.Departments.Add(department);
        _context.SaveChanges();

        var retrieved = _context.Departments.Find(department.DepartmentID);
        Assert.NotNull(retrieved);
        Assert.Equal("Engineering", retrieved.Name);
        Assert.Equal(500000, retrieved.Budget);
    }

    [Fact]
    public void CanAddAndRetrieveEnrollment()
    {
        var student = new Student
        {
            FirstMidName = "Enroll",
            LastName = "Test",
            EnrollmentDate = DateTime.Now
        };
        _context.Students.Add(student);

        var dept = new Department { Name = "D", Budget = 1000, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = 5678,
            Title = "Enroll Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var enrollment = new Enrollment
        {
            StudentID = student.ID,
            CourseID = course.CourseID,
            Grade = Grade.A
        };
        _context.Enrollments.Add(enrollment);
        _context.SaveChanges();

        var retrieved = _context.Enrollments.First(e => e.StudentID == student.ID);
        Assert.Equal(Grade.A, retrieved.Grade);
        Assert.Equal(course.CourseID, retrieved.CourseID);
    }

    [Fact]
    public void CanAddAndRetrieveOfficeAssignment()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Office",
            LastName = "Test",
            HireDate = DateTime.Now
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var office = new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Room 101"
        };
        _context.OfficeAssignments.Add(office);
        _context.SaveChanges();

        var retrieved = _context.OfficeAssignments.Find(instructor.ID);
        Assert.NotNull(retrieved);
        Assert.Equal("Room 101", retrieved.Location);
    }

    [Fact]
    public void CanAddAndRetrieveCourseAssignment()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Assign",
            LastName = "Test",
            HireDate = DateTime.Now
        };
        _context.Instructors.Add(instructor);

        var dept = new Department { Name = "D2", Budget = 1000, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = 9012,
            Title = "Assign Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var assignment = new CourseAssignment
        {
            InstructorID = instructor.ID,
            CourseID = course.CourseID
        };
        _context.CourseAssignments.Add(assignment);
        _context.SaveChanges();

        var retrieved = _context.CourseAssignments
            .SingleOrDefault(ca => ca.InstructorID == instructor.ID && ca.CourseID == course.CourseID);
        Assert.NotNull(retrieved);
    }

    [Fact]
    public void CourseAssignment_HasCompositeKey()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Key",
            LastName = "Test",
            HireDate = DateTime.Now
        };
        _context.Instructors.Add(instructor);

        var dept = new Department { Name = "D3", Budget = 1000, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = 3456,
            Title = "Key Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        // Add first assignment
        _context.CourseAssignments.Add(new CourseAssignment
        {
            InstructorID = instructor.ID,
            CourseID = course.CourseID
        });
        _context.SaveChanges();

        // Adding duplicate composite key should throw
        _context.CourseAssignments.Add(new CourseAssignment
        {
            InstructorID = instructor.ID,
            CourseID = course.CourseID
        });
        Assert.Throws<ArgumentException>(() => _context.SaveChanges());
    }

    [Fact]
    public void Student_Enrollments_NavigationProperty_Works()
    {
        var student = new Student
        {
            FirstMidName = "Nav",
            LastName = "Test",
            EnrollmentDate = DateTime.Now
        };
        _context.Students.Add(student);

        var dept = new Department { Name = "NavD", Budget = 1000, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = 7890,
            Title = "Nav Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        _context.Enrollments.Add(new Enrollment
        {
            StudentID = student.ID,
            CourseID = course.CourseID,
            Grade = Grade.B
        });
        _context.SaveChanges();

        var loadedStudent = _context.Students
            .Include(s => s.Enrollments)
            .Single(s => s.ID == student.ID);

        Assert.NotNull(loadedStudent.Enrollments);
        Assert.Single(loadedStudent.Enrollments);
    }

    [Fact]
    public void Instructor_OfficeAssignment_OneToOne_Works()
    {
        var instructor = new Instructor
        {
            FirstMidName = "OneToOne",
            LastName = "Test",
            HireDate = DateTime.Now
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        _context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Building A"
        });
        _context.SaveChanges();

        var loaded = _context.Instructors
            .Include(i => i.OfficeAssignment)
            .Single(i => i.ID == instructor.ID);

        Assert.NotNull(loaded.OfficeAssignment);
