using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class ModelTests
{
    #region Person / Student / Instructor

    [Fact]
    public void Person_FullName_ReturnsConcatenatedName()
    {
        var student = new Student
        {
            FirstMidName = "John",
            LastName = "Doe"
        };

        Assert.Equal("Doe, John", student.FullName);
    }

    [Fact]
    public void Instructor_FullName_ReturnsConcatenatedName()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Jane",
            LastName = "Smith"
        };

        Assert.Equal("Smith, Jane", instructor.FullName);
    }

    [Fact]
    public void Student_IsSubclassOfPerson()
    {
        var student = new Student();
        Assert.IsAssignableFrom<Person>(student);
    }

    [Fact]
    public void Instructor_IsSubclassOfPerson()
    {
        var instructor = new Instructor();
        Assert.IsAssignableFrom<Person>(instructor);
    }

    #endregion

    #region ErrorViewModel

    [Fact]
    public void ErrorViewModel_ShowRequestId_TrueWhenSet()
    {
        var model = new ErrorViewModel { RequestId = "abc123" };
        Assert.True(model.ShowRequestId);
    }

    [Fact]
    public void ErrorViewModel_ShowRequestId_FalseWhenNull()
    {
        var model = new ErrorViewModel { RequestId = null };
        Assert.False(model.ShowRequestId);
    }

    [Fact]
    public void ErrorViewModel_ShowRequestId_FalseWhenEmpty()
    {
        var model = new ErrorViewModel { RequestId = "" };
        Assert.False(model.ShowRequestId);
    }

    #endregion

    #region Course

    [Fact]
    public void Course_Properties_SetAndGetCorrectly()
    {
        var course = new Course
        {
            CourseID = 100,
            Title = "Test Course",
            Credits = 4,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/images/test.jpg"
        };

        Assert.Equal(100, course.CourseID);
        Assert.Equal("Test Course", course.Title);
        Assert.Equal(4, course.Credits);
        Assert.Equal(1, course.DepartmentID);
        Assert.Equal("/images/test.jpg", course.TeachingMaterialImagePath);
    }

    #endregion

    #region Department

    [Fact]
    public void Department_Properties_SetAndGetCorrectly()
    {
        var startDate = DateTime.Parse("2023-01-01");
        var department = new Department
        {
            DepartmentID = 5,
            Name = "Science",
            Budget = 250000,
            StartDate = startDate,
            InstructorID = 10
        };

        Assert.Equal(5, department.DepartmentID);
        Assert.Equal("Science", department.Name);
        Assert.Equal(250000, department.Budget);
        Assert.Equal(startDate, department.StartDate);
        Assert.Equal(10, department.InstructorID);
    }

    [Fact]
    public void Department_InstructorID_CanBeNull()
    {
        var department = new Department { InstructorID = null };
        Assert.Null(department.InstructorID);
    }

    #endregion

    #region Enrollment

    [Fact]
    public void Enrollment_Grade_CanBeNull()
    {
        var enrollment = new Enrollment { Grade = null };
        Assert.Null(enrollment.Grade);
    }

    [Fact]
    public void Enrollment_Properties_SetCorrectly()
    {
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 100,
            StudentID = 200,
            Grade = Grade.A
        };

        Assert.Equal(1, enrollment.EnrollmentID);
        Assert.Equal(100, enrollment.CourseID);
        Assert.Equal(200, enrollment.StudentID);
        Assert.Equal(Grade.A, enrollment.Grade);
    }

    [Theory]
    [InlineData(Grade.A)]
    [InlineData(Grade.B)]
    [InlineData(Grade.C)]
    [InlineData(Grade.D)]
    [InlineData(Grade.F)]
    public void Enrollment_AllGradeValues_AreValid(Grade grade)
    {
        var enrollment = new Enrollment { Grade = grade };
        Assert.Equal(grade, enrollment.Grade);
    }

    #endregion

    #region Notification

    [Fact]
    public void Notification_Properties_SetCorrectly()
    {
        var now = DateTime.Now;
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "New student created",
            CreatedAt = now,
            CreatedBy = "Admin",
            IsRead = false,
            ReadAt = null
        };

        Assert.Equal(1, notification.Id);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("42", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("New student created", notification.Message);
        Assert.Equal(now, notification.CreatedAt);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
        Assert.Null(notification.ReadAt);
    }

    [Fact]
    public void Notification_ReadAt_CanBeSet()
    {
        var readTime = DateTime.Now;
        var notification = new Notification
        {
            IsRead = true,
            ReadAt = readTime
        };

        Assert.True(notification.IsRead);
        Assert.Equal(readTime, notification.ReadAt);
    }

    #endregion

    #region EntityOperation Enum

    [Fact]
    public void EntityOperation_HasExpectedValues()
    {
        Assert.Equal(0, (int)EntityOperation.CREATE);
        Assert.Equal(1, (int)EntityOperation.UPDATE);
        Assert.Equal(2, (int)EntityOperation.DELETE);
    }

    #endregion

    #region OfficeAssignment

    [Fact]
    public void OfficeAssignment_Properties_SetCorrectly()
    {
        var office = new OfficeAssignment
        {
            InstructorID = 5,
            Location = "Room 101"
        };

        Assert.Equal(5, office.InstructorID);
        Assert.Equal("Room 101", office.Location);
    }

    #endregion

    #region CourseAssignment

    [Fact]
    public void CourseAssignment_Properties_SetCorrectly()
    {
        var assignment = new CourseAssignment
        {
            InstructorID = 3,
            CourseID = 1050
        };

        Assert.Equal(3, assignment.InstructorID);
        Assert.Equal(1050, assignment.CourseID);
    }

    #endregion
}

